import{_ as e,c as a,o as t,V as l}from"./chunks/framework.yB9ribBw.js";const m=JSON.parse('{"title":"前端路由和后端路由的区别","description":"","frontmatter":{},"headers":[],"relativePath":"guide/interview/vue/路由/前端路由和后端路由的区别.md","filePath":"guide/interview/vue/路由/前端路由和后端路由的区别.md","lastUpdated":1719242077000}'),i={name:"guide/interview/vue/路由/前端路由和后端路由的区别.md"},o=l('<h1 id="前端路由和后端路由的区别" tabindex="-1">前端路由和后端路由的区别 <a class="header-anchor" href="#前端路由和后端路由的区别" aria-label="Permalink to &quot;前端路由和后端路由的区别&quot;">​</a></h1><h2 id="什么是路由" tabindex="-1">什么是路由 <a class="header-anchor" href="#什么是路由" aria-label="Permalink to &quot;什么是路由&quot;">​</a></h2><p>路由是根据不同的 url 地址展示不同的内容或页面；</p><h2 id="前端路由" tabindex="-1">前端路由 <a class="header-anchor" href="#前端路由" aria-label="Permalink to &quot;前端路由&quot;">​</a></h2><p>很重要的一点是页面不刷新，前端路由就是把不同路由对应不同的内容或页面的任务交给前端来做，每跳转到不同的URL都是使用前端的锚点路由.</p><p>随着（SPA）单页应用的不断普及，前后端开发分离，目前项目基本都使用前端路由，在项目使用期间页面不会重新加载。</p><p>优点:</p><ol><li>用户体验好，和后台网速没有关系，不需要每次都从服务器全部获取，快速展现给用户</li><li>可以再浏览器中输入指定想要访问的url路径地址</li><li>实现了前后端的分离，方便开发。有很多框架都带有路由功能模块。</li></ol><p>缺点:</p><ol><li><p>使用浏览器的前进，后退键的时候会重新发送请求，没有合理地利用缓存</p></li><li><p>单页面无法记住之前滚动的位置，无法在前进，后退的时候记住滚动的位置</p></li></ol><h2 id="后端路由" tabindex="-1">后端路由 <a class="header-anchor" href="#后端路由" aria-label="Permalink to &quot;后端路由&quot;">​</a></h2><p>浏览器在地址栏中切换不同的url时，每次都向后台服务器发出请求，服务器响应请求，在后台拼接html文件传给前端显示, 返回不同的页面,</p><p>意味着浏览器会刷新页面，网速慢的话说不定屏幕全白再有新内容。后端路由的另外一个极大的问题就是 前后端不分离。</p><p>优点：</p><ol><li>分担了前端的压力，html和数据的拼接都是由服务器完成。</li></ol><p>缺点：</p><ol><li>当项目十分庞大时，加大了服务器端的压力，同时在浏览器端不能输入制定的url路径进行指定模块的访问。另外一个就是如果当前网速过慢，那将会延迟页面的加载，对用户体验不是很友好。</li></ol>',17),r=[o];function _(p,n,d,s,h,c){return t(),a("div",null,r)}const f=e(i,[["render",_]]);export{m as __pageData,f as default};
